function solve(m, n, waitCost) {
    const INF = Infinity;
    const dpOdd = new Array(m).fill(0).map(() => new Array(n).fill(INF));
    const dpEven = new Array(m).fill(0).map(() => new Array(n).fill(INF));
    dpOdd[0][0] = 1;

    let heap = [[1, 0, 0, 1]];
    const directions = [[0, 1], [1, 0]];

    while (heap.length > 0) {
        const [cost, i, j, parity] = heap.shift();

        if (parity === 1) {
            if (cost > dpOdd[i][j]) continue;
        } else {
            if (cost > dpEven[i][j]) continue;
        }

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        if (parity === 1) {
            for (const [dx, dy] of directions) {
                const ni = i + dx;
                const nj = j + dy;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    const newCost = cost + (ni + 1) * (nj + 1);
                    if (newCost < dpEven[ni][nj]) {
                        dpEven[ni][nj] = newCost;
                        heap.push([newCost, ni, nj, 0]);
                    }
                }
            }
        } else {
            const newCost = cost + waitCost[i][j];
            if (newCost < dpOdd[i][j]) {
                dpOdd[i][j] = newCost;
                heap.push([newCost, i, j, 1]);
            }
        }
    }

    return Math.min(dpOdd[m - 1][n - 1], dpEven[m - 1][n - 1]);
}
