    const pq = [];
    // Initialize the priority queue with the starting state
    pq.push([1, 0, 0, 1]);
    // Create a 2D array of Maps to track the minimum cost for each (i,j, time)
    const dist = new Array(m).fill().map(() => new Array(n).fill().map(() => new Map()));
    dist[0][0].set(1, 1);

    while (pq.length > 0) {
        // Sort the priority queue to get the smallest cost element
        pq.sort((a, b) => a[0] - b[0]);
        const [cost, i, j, time] = pq.shift();

        // Check if we reached the destination
        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        // Check if the current state is already processed with a lower cost
        if (dist[i][j].has(time) && dist[i][j].get(time) < cost) {
            continue;
        }

        // Determine if current time is even or odd
        const isEven = time % 2 === 0;

        if (isEven) {
            // Must wait
            const new_time = time + 1;
            const new_cost = cost + waitCost[i][j];
            if (!dist[i][j].has(new_time) || new_cost < dist[i][j].get(new_time)) {
                dist[i][j].set(new_time, new_cost);
                pq.push([new_cost, i, j, new_time]);
